import{_ as a,o,c as i,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Peekaboo Bridge","description":"","frontmatter":{"summary":"PeekabooBridge integration for macOS UI automation","read_when":["Hosting PeekabooBridge in OpenSoul.app","Integrating Peekaboo via Swift Package Manager","Changing PeekabooBridge protocol/paths"],"title":"Peekaboo Bridge"},"headers":[],"relativePath":"platforms/mac/peekaboo.md","filePath":"platforms/mac/peekaboo.md","lastUpdated":null}'),t={name:"platforms/mac/peekaboo.md"};function r(n,e,l,h,d,p){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="peekaboo-bridge-macos-ui-automation" tabindex="-1"><a class="header-anchor" href="#peekaboo-bridge-macos-ui-automation">#</a> Peekaboo Bridge (macOS UI automation)</h1><p>OpenSoul can host <strong>PeekabooBridge</strong> as a local, permission‑aware UI automation broker. This lets the <code>peekaboo</code> CLI drive UI automation while reusing the macOS app’s TCC permissions.</p><h2 id="what-this-is-and-isn-t" tabindex="-1"><a class="header-anchor" href="#what-this-is-and-isn-t">#</a> What this is (and isn’t)</h2><ul><li><strong>Host</strong>: OpenSoul.app can act as a PeekabooBridge host.</li><li><strong>Client</strong>: use the <code>peekaboo</code> CLI (no separate <code>opensoul ui ...</code> surface).</li><li><strong>UI</strong>: visual overlays stay in Peekaboo.app; OpenSoul is a thin broker host.</li></ul><h2 id="enable-the-bridge" tabindex="-1"><a class="header-anchor" href="#enable-the-bridge">#</a> Enable the bridge</h2><p>In the macOS app:</p><ul><li>Settings → <strong>Enable Peekaboo Bridge</strong></li></ul><p>When enabled, OpenSoul starts a local UNIX socket server. If disabled, the host is stopped and <code>peekaboo</code> will fall back to other available hosts.</p><h2 id="client-discovery-order" tabindex="-1"><a class="header-anchor" href="#client-discovery-order">#</a> Client discovery order</h2><p>Peekaboo clients typically try hosts in this order:</p><ol><li>Peekaboo.app (full UX)</li><li>Claude.app (if installed)</li><li>OpenSoul.app (thin broker)</li></ol><p>Use <code>peekaboo bridge status --verbose</code> to see which host is active and which socket path is in use. You can override with:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PEEKABOO_BRIDGE_SOCKET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/bridge.sock</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="security-permissions" tabindex="-1"><a class="header-anchor" href="#security-permissions">#</a> Security &amp; permissions</h2><ul><li>The bridge validates <strong>caller code signatures</strong>; an allowlist of TeamIDs is enforced (Peekaboo host TeamID + OpenSoul app TeamID).</li><li>Requests time out after ~10 seconds.</li><li>If required permissions are missing, the bridge returns a clear error message rather than launching System Settings.</li></ul><h2 id="snapshot-behavior-automation" tabindex="-1"><a class="header-anchor" href="#snapshot-behavior-automation">#</a> Snapshot behavior (automation)</h2><p>Snapshots are stored in memory and expire automatically after a short window. If you need longer retention, re‑capture from the client.</p><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting">#</a> Troubleshooting</h2><ul><li>If <code>peekaboo</code> reports “bridge client is not authorized”, ensure the client is properly signed or run the host with <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code> in <strong>debug</strong> mode only.</li><li>If no hosts are found, open one of the host apps (Peekaboo.app or OpenSoul.app) and confirm permissions are granted.</li></ul>',19)])])}const b=a(t,[["render",r]]);export{u as __pageData,b as default};
